def solve(input_data):
    # Validate inputs vs contract
    if not isinstance(input_data, dict):
        raise ValueError("Input must be a dictionary")

    required_keys = ['genome_sequence', 'annotations']
    for key in required_keys:
        if key not in input_data:
            raise ValueError(f"Missing required key: {key}")

    genome_sequence = input_data['genome_sequence']
    annotations = input_data['annotations']

    # Implement core logic
    if not isinstance(genome_sequence, str) or not isinstance(annotations, list):
        raise ValueError("Invalid types for genome_sequence or annotations")

    # Check edge cases
    if len(genome_sequence) == 0:
        raise ValueError("Genome sequence cannot be empty")

    if len(annotations) == 0:
        raise ValueError("Annotations cannot be empty")

    # Example core logic: Count occurrences of annotations in the genome sequence
    results = {}
    for annotation in annotations:
        if not isinstance(annotation, str):
            raise ValueError("Annotations must be strings")
        results[annotation] = genome_sequence.count(annotation)

    return results
